  // Block during async operations
  if (this.saving() || this.loading()) return false;

  // Required fields (non-empty after trim)
  const n = this.name().trim();
  if (!n || n.length > 255) return false;

  // Pattern validation
  const s = this.slug().trim();
  if (!s || s.length > 100) return false;
  if (!SLUG_REGEX.test(s)) return false;

  // Field-level error arrays (catches duplicates, pattern violations)
  if (this.nameErrors().length > 0) return false;
  if (this.slugErrors().length > 0) return false;

  return true;
