slugManuallyEdited = signal(false);

constructor() {
  // Auto-generate slug from name in create mode only
  effect(() => {
    const n = this.name();
    if (this.isEditMode() || this.slugManuallyEdited()) return;
    this.slug.set(this.generateSlug(n));
  });
}

onSlugInput(value: string): void {
  this.slugManuallyEdited.set(true);
  this.slug.set(value);
}

private generateSlug(name: string): string {
  return name
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .substring(0, 100);
}

async onDelete(): Promise<void> {
  const selected = this.selectedItems();
  if (selected.length === 0) return;

  const confirmed = await this.confirmService.confirmDelete(
    await firstValueFrom(this.translate.get('action_delete_title')),
    await firstValueFrom(this.translate.get('action_delete_confirm', { count: selected.length })),
  );
  if (!confirmed) return;

  try {
    await this.actionService.delete({ entityKeys: selected.map(s => s.id) });
    this.toastr.success(
      await firstValueFrom(this.translate.get('action_delete_success')),
    );
    await this.load();
  } catch {
    this.toastr.error(
      await firstValueFrom(this.translate.get('action_delete_error')),
    );
  }
}

async onToggleStatus(): Promise<void> {
  const action = this.action();
  if (!action) return;

  const isActive = action.status.name === 'Active';
  const confirmed = await this.confirmService.confirm(
    await firstValueFrom(this.translate.get(
      isActive ? 'action_deactivate_confirm' : 'action_activate_confirm',
      { name: action.name },
    )),
    await firstValueFrom(this.translate.get(
      isActive ? 'action_deactivate_title' : 'action_activate_title',
    )),
    {
      variant: isActive ? 'danger' : 'primary',
      confirmLabel: await firstValueFrom(this.translate.get(
        isActive ? 'common_deactivate' : 'common_activate',
      )),
    },
  );
  if (!confirmed) return;

  try {
    const newStatus: EnumDTO = isActive
      ? { id: 1, name: 'Inactive' }
      : { id: 0, name: 'Active' };
    await this.actionService.updateStatus(action.id, { status: newStatus });
    this.toastr.success(
      await firstValueFrom(this.translate.get('action_status_updated')),
    );
    await this.loadEntity(action.id);
  } catch {
    this.errorMessage.set(
      await firstValueFrom(this.translate.get('action_status_error')),
    );
  }
}

